    {
        DialogRunbase dialog = super();

        dialogFieldCreditLimit = dialog.addFieldValue(extendedTypeStr(CustCreditMax), newCreditLimit, "New credit limit");
        dialogFieldPercentage = dialog.addFieldValue(extendedTypeStr(Percent), adjustmentPercentage, "Adjustment percentage");

        dialog.addTabPage("Selection criteria");
        dialog.addQueryBuild(queryRun);

        return dialog;
    }

