    /// Execute business logic
    /// </summary>
    public void run()
    {
        CustTable       custTable;
        Counter         processedRecords;
        CustCreditMax   calculatedLimit;

        try
        {
            ttsbegin;

            queryRun.reset();
            while (queryRun.next())
            {
                custTable = queryRun.get(tableNum(CustTable));

                if (adjustmentPercentage != 0)
                {
                    calculatedLimit = custTable.CreditMax * (100 + adjustmentPercentage) / 100;
                }
                else
                {
                    calculatedLimit = newCreditLimit;
                }

                custTable.selectForUpdate(true);
                custTable.CreditMax = calculatedLimit;
                custTable.update();

                processedRecords++;

                if (processedRecords mod 100 == 0)
                {
                    info(strFmt("Processed %1 customers...", processedRecords));
                }
            }

            ttscommit;
            info(strFmt("Successfully updated %1 customer credit limits.", processedRecords));
        }
        catch (Exception::Error)
        {
            ttsabort;
            error("An error occurred during credit limit update.");
            throw Exception::Error;
        }
    }

    /// <summary>
    /// Pack parameters for serialization
    /// </summary>
    public container pack()
    {
        return [#CurrentVersion, #CurrentList, queryRun.pack()];
    }

