    /// Unpack parameters from serialization
    /// </summary>
    public boolean unpack(container _packedClass)
    {
        Version     version = RunBase::getVersion(_packedClass);
        container   queryCon;

        switch (version)
        {
            case #CurrentVersion:
                [version, #CurrentList, queryCon] = _packedClass;
                queryRun = new QueryRun(queryCon);
                break;
            default:
                return false;
        }

        return true;
    }
}

